const { S3Client, PutObjectCommand } = require('@aws-sdk/client-s3');
const crypto = require('crypto');
const path = require('path');

const s3Client = new S3Client({ region: process.env.AWS_REGION });
const BUCKET_NAME = process.env.UPLOADS_BUCKET;
const MAX_FILE_SIZE = parseInt(process.env.MAX_FILE_SIZE || '5242880', 10); // 5MB default
const ALLOWED_EXTENSIONS = new Set(['.jpg', '.jpeg', '.png', '.gif', '.pdf', '.txt', '.csv', '.doc', '.docx']);
const ALLOWED_CONTENT_TYPES = new Set([
  'image/jpeg', 'image/png', 'image/gif',
  'application/pdf', 'text/plain', 'text/csv',
  'application/msword',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
]);

exports.handler = async (event) => {
  try {
    // Require authentication - reject if no valid auth context
    const requestContext = event.requestContext;
    const authorizer = requestContext && requestContext.authorizer;

    if (!authorizer || !authorizer.claims || !authorizer.claims.sub) {
      return buildResponse(401, { error: 'Authentication required. Provide a valid authorization token.' });
    }

    const userId = authorizer.claims.sub;

    if (event.httpMethod !== 'POST') {
      return buildResponse(405, { error: 'Method not allowed' });
    }

    let body;
    try {
      body = event.isBase64Encoded
        ? JSON.parse(Buffer.from(event.body, 'base64').toString('utf-8'))
        : JSON.parse(event.body);
    } catch (parseError) {
      return buildResponse(400, { error: 'Invalid JSON in request body' });
    }

    if (!body || !body.fileContent || !body.fileName || !body.contentType) {
      return buildResponse(400, { error: 'Missing required fields: fileContent, fileName, contentType' });
    }

    // Validate content type against allowlist
    const contentType = body.contentType.toLowerCase().trim();
    if (!ALLOWED_CONTENT_TYPES.has(contentType)) {
      return buildResponse(400, {
        error: `Content type not allowed: ${contentType}. Allowed types: ${[...ALLOWED_CONTENT_TYPES].join(', ')}`
      });
    }

    // Sanitize and validate file name - prevent path traversal
    const originalFileName = path.basename(body.fileName);
    const fileExtension = path.extname(originalFileName).toLowerCase();

    if (!fileExtension || !ALLOWED_EXTENSIONS.has(fileExtension)) {
      return buildResponse(400, {
        error: `File extension not allowed. Allowed extensions: ${[...ALLOWED_EXTENSIONS].join(', ')}`
      });
    }

    // Validate filename contains only safe characters after basename extraction
    const safeNamePattern = /^[a-zA-Z0-9._-]+$/;
    if (!safeNamePattern.test(originalFileName)) {
      return buildResponse(400, { error: 'File name contains invalid characters. Use only alphanumeric, dots, hyphens, and underscores.' });
    }

    // Decode file content and validate size
    let fileBuffer;
    try {
      fileBuffer = Buffer.from(body.fileContent, 'base64');
    } catch (decodeError) {
      return buildResponse(400, { error: 'Invalid base64 file content' });
    }

    if (fileBuffer.length === 0) {
      return buildResponse(400, { error: 'File content is empty' });
    }

    if (fileBuffer.length > MAX_FILE_SIZE) {
      return buildResponse(400, {
        error: `File size ${fileBuffer.length} exceeds maximum allowed size of ${MAX_FILE_SIZE} bytes`
      });
    }

    // Generate a unique, non-guessable key scoped to the authenticated user
    const uniqueId = crypto.randomUUID();
    const sanitizedName = originalFileName.replace(/[^a-zA-Z0-9._-]/g, '_');
    const s3Key = `uploads/${userId}/${uniqueId}/${sanitizedName}`;

    const putCommand = new PutObjectCommand({
      Bucket: BUCKET_NAME,
      Key: s3Key,
      Body: fileBuffer,
      ContentType: contentType,
      ServerSideEncryption: 'aws:kms',
      Metadata: {
        'uploaded-by': userId,
        'original-filename': sanitizedName,
        'upload-timestamp': new Date().toISOString()
      }
    });

    await s3Client.send(putCommand);

    return buildResponse(200, {
      message: 'File uploaded successfully',
      fileKey: s3Key,
      size: fileBuffer.length
    });

  } catch (error) {
    console.error('Upload error:', error.name, error.message);
    return buildResponse(500, { error: 'Internal server error' });
  }
};

function buildResponse(statusCode, body) {
  return {
    statusCode,
    headers: {
      'Content-Type': 'application/json',
      'X-Content-Type-Options': 'nosniff',
      'Strict-Transport-Security': 'max-age=63072000; includeSubDomains; preload',
      'Cache-Control': 'no-store'
    },
    body: JSON.stringify(body)
  };
}

